) VALUES
  ('Dan Jovevski', 'Founder & CEO', 'Founder & CEO at WeMoney · We’re #HIRING at WeMoney!Build with us. Helping Aussies pay down debt faster. Over 1M+ downloads and growing.If you''re keen to solve real problems and build with purpose — come join us.Read Building Australia’s Financial Future — www.wemoney.com.au/letter-to-buildersDM me or check out open roles!#WeMoney #Hiring #Fintech #BuildWithUsPassionate FinTech entrepreneur (with an exit), transformational leader, technologist, focused on driving results across end-to-end value chains in financial se', 'Greater Perth Area', 'Senior operator with extensive ANZ market experience.', ARRAY['International Founder', 'Fintech Founder'], 'https://linkedin.com/in/danieljovevski', NULL, NULL, 'WeMoney', FALSE, '[{"name": "WeMoney"}, {"name": "Strategica.io"}]'::jsonb, 'usa', ARRAY['usa', 'australia'], NULL, 'dan-jovevski', 'International Founder', ARRAY['international_entrant'], TRUE, FALSE),
  ('Martin McCann', 'Founder and CEO', 'Founder and CEO @ Trade Ledger™ | Driving Business Growth · I am an entrepreneur and strategic advisor dedicated to helping commercial banks modernise through Enterprise AI. As the Founder and CEO of Trade Ledger™ for nearly a decade, I built a digital platform that redefined cash flow lending through unparalleled access to real-time B2B transaction data.My mission has evolved alongside the technology: I lead AI vision and strategy, helping banks transition from traditional lending models to AI-driven enterprise architectures. By drawing on my expertise', 'Sydney, New South Wales, Australia', 'Senior operator with extensive ANZ market experience.', ARRAY['International Founder', 'Technology / Product'], 'https://linkedin.com/in/mccannmartin', NULL, NULL, 'Trade Ledger™', FALSE, '[{"name": "Trade Ledger\u2122"}, {"name": "The Digital Institute"}]'::jsonb, 'uk', ARRAY['uk', 'australia'], NULL, 'martin-mccann', 'International Founder', ARRAY['international_entrant'], TRUE, FALSE),
