  ('Cindy Callander', 'Senior Trade Specialist', 'Senior Trade Specialist, Science and Technology · I am an economic development, trade, strategy and governance expert with 24 years'' experience in public and private sector service delivery industries and 18 years'' in management. During my career, I have utilised networks and cross agency relationships to deliver advice and projects and operationalise strategy in the fields of precinct development, international education, trade and investment and governance. I have managed government budgets in local and state sectors and successfully led team', 'Greater Melbourne Area', 'Senior operator with extensive ANZ market experience.', ARRAY['Trade & Government'], 'https://linkedin.com/in/cindycallander', NULL, NULL, 'Scottish Development International', FALSE, '[{"name": "Scottish Development International"}, {"name": "Global Victoria"}]'::jsonb, 'usa', ARRAY['usa', 'australia'], NULL, 'cindy-callander', 'Trade & Government', ARRAY['international_entrant'], TRUE, FALSE),
  ('Samantha Warner', 'Assistant Market Advisor', 'Assistant Market Advisor at Enterprise Ireland · I am an Assistant Market Advisor at Enterprise Ireland, the trade and innovation agency of the Irish government.My core competencies include Communication, market research, and project management. I assist in identifying and developing market opportunities, creating and executing market entry and expansion strategies, and building and maintaining strong relationships with key stakeholders. I also assist in coordinating events for Enterprise Ireland ANZ and am Office Manager for the Sydney office', 'Greater Sydney Area', 'Senior operator with extensive ANZ market experience.', ARRAY['Trade & Government', 'Cross-border'], 'https://linkedin.com/in/samantha-warner-3b326591', NULL, NULL, 'Enterprise Ireland', FALSE, '[{"name": "Enterprise Ireland"}, {"name": "SMEC"}]'::jsonb, NULL, ARRAY['australia'], NULL, 'samantha-warner', 'Trade & Government', ARRAY['international_entrant'], TRUE, FALSE),
  ('Tess Thomas', 'Associate Director', 'Associate Director, Strategic Advisory & Concierge, Investment Delivery Authority · An accomplished leader with over 10 years’ experience across the UK, Australia, NZ and South America in project management, facilitation, strategic thinking and business development. I apply business acumen and analytical rigour to assist organisations with their international expansion plans. I have a deep understanding of the Aus-UK business synergies, particularly in FinTech and Capital Investment. In my current role, I manage small teams to provide tailored solutions to businesses of differe', 'Greater Sydney Area', '10+ years operating experience in ANZ and international markets.', ARRAY['Trade & Government', 'Cross-border'], 'https://linkedin.com/in/tlaroo', NULL, NULL, 'Premier''s Department NSW', FALSE, '[{"name": "Premier''s Department NSW"}, {"name": "Investment NSW"}]'::jsonb, 'uk', ARRAY['uk', 'australia'], NULL, 'tess-thomas', 'Trade & Government', ARRAY['international_entrant'], TRUE, FALSE),
  ('Mantas Aleksiejevas', 'CEO & Co-Founder', 'CEO & Co-Founder at Cor | Building Obi, Voice AI Agent for Customer Onboarding & Activation · I started my career helping startups grow. At Google, I built and ran startup growth programs across Europe, working with companies in fintech, e-commerce, travel, gaming, cybersecurity, and SaaS. Later, I moved into commercial leadership roles at three growth-stage ventures in finance, real estate, and marketplaces.One thing became clear: customer retention and expansion were always the hardest problems. Companies threw people at the problem, but it didn’t scale.That’s why I co-founded Cor. We’', 'Australia', 'Senior operator with extensive ANZ market experience.', ARRAY['International Founder', 'Technology / Product'], 'https://linkedin.com/in/mantasaleks', NULL, NULL, 'Cor', FALSE, '[{"name": "Cor"}, {"name": "Breezit"}]'::jsonb, 'uk', ARRAY['uk', 'australia'], NULL, 'mantas-aleksiejevas', 'International Founder', ARRAY['both'], TRUE, FALSE),
  ('Brendan Widdowson', 'Chief Commercial Officer', 'Chief Commercial Officer at Banjo · An established business development leader in the fintech sector, with proven experience across payments, open banking, lending and data & analytics in Australia and Europe.Entrepreneurially driven and passionate about helping businesses, has defined and implemented go-to-market strategies, built sales and marketing teams, developed partnerships and won new business at SME to enterprise level – helping to establish and scale multiple fintech businesses.M: 0409433910 E: bwiddowson@banjoloans.com', 'Greater Melbourne Area', 'Senior operator with extensive ANZ market experience.', ARRAY['Trade & Government', 'Sales / GTM'], 'https://linkedin.com/in/bjwiddowson', NULL, NULL, 'Banjo - Business Loans', FALSE, '[{"name": "Banjo - Business Loans"}, {"name": "Fire"}]'::jsonb, 'uk', ARRAY['uk', 'australia'], NULL, 'brendan-widdowson', 'Trade & Government', ARRAY['international_entrant'], TRUE, FALSE),
