  ('Mark Ellis', 'Chief of Staff', 'Chief of Staff @ Salient | Recruitment | SaaS | Tech | GTM | Start Ups | VCs | Partnerships · I''m a Belfast-born Recruiter now based in Sydney, working with Salient — APAC’s first SaaS recruitment agency.What We Do at Salient:We’re a specialist tech and sales recruitment partner for SaaS and tech-centred companies across Australia, Southeast Asia, Japan & the Middle East.From seed stage to scale-up, we help high-growth businesses find exceptional talent across:• Sales• Product• Engineering• Customer Success• Post-SalesFounded in 2008, we’ve been at the forefront of tech hiring in APAC fo', 'Sydney, New South Wales, Australia', 'Senior operator with extensive ANZ market experience.', ARRAY['Scaled Founder', 'Sector Expert: SaaS'], 'https://linkedin.com/in/markadamellis', NULL, NULL, 'Salient Group', FALSE, '[{"name": "Salient Group"}, {"name": "Lendlease"}]'::jsonb, 'uk', ARRAY['uk', 'australia'], NULL, 'mark-ellis', 'Scaled Founder', ARRAY['international_entrant'], TRUE, FALSE),
  ('Yanir Yakutiel ️', 'Founder & CEO', 'Founder & CEO at Lumi · We have a saying at Lumi: "With us, you''re not a loan." We''re a FinTech disruptor that doesn''t speak, think or act like a bank. This is the essence of what drives us to offer superior funding solutions to our clients. We harness real-time big data to assess creditworthiness for SMEs that are experiencing difficulty securing finance from banks and traditional lenders. This allows us to offer an alternative source of capital to small business; a new way to manage their cash flow and enable future', 'Greater Sydney Area', 'Senior operator with extensive ANZ market experience.', ARRAY['International Founder', 'Fintech Founder'], 'https://linkedin.com/in/yaniryakutiel', NULL, NULL, 'Lumi', FALSE, '[{"name": "Lumi"}, {"name": "Sail Finance"}]'::jsonb, 'france', ARRAY['france', 'australia'], NULL, 'yanir-yakutiel', 'International Founder', ARRAY['both'], TRUE, FALSE)
